/*
 * Archivo: c_basics.c
 * Autor: Alejo
 * Descripción: Ejemplo simple que muestra los conceptos básicos de C
 *               (variables, tipos de datos, estructuras de control, funciones y
 *               comentarios).  Todos los comentarios están en español.
 */

#include <stdio.h>

/*
 * 1. Tipos de datos primitivos
 *    - int   : enteros con signo (usado para contadores, índices, etc.)
 *    - float : números reales con coma flotante (p.ej., 3.14)
 *    - double: doble precisión, mayor rango y exactitud que float
 *    - char  : carácter único (usa comillas simples, ej. 'a')
 *    - bool  : tipo lógico (C99 y posteriores con stdbool.h)
 */

#include <stdbool.h>  // Para usar bool, true y false

/*
 * 2. Variables y su inicialización
 *    En C se declara el tipo seguido del nombre.  Puede asignarse
 *    valor en la misma línea o después con el operador =.
 */
int edad = 25;           // variable entera
float pi = 3.14159f;     // variable de tipo float (la 'f' indica float)
char letra = 'A';        // variable de tipo char
bool estudiante = true; // variable booleana

/*
 * 3. Función principal (punto de entrada del programa)
 *    - return 0; indica que el programa terminó sin errores.
 */
int main(void) {
    /*
     * 4. Salida a la consola con printf
     *    %d -> entero, %f -> flotante, %c -> carácter, %s -> cadena
     */
    printf("Hola, mundo!\n");
    printf("Edad: %d años\n", edad);
    printf("PI: %f\n", pi);
    printf("Letra: %c\n", letra);
    printf("¿Soy estudiante? %s\n", estudiante ? "Sí" : "No");

    /*
     * 5. Estructuras de control
     *    - if / else
     *    - while
     *    - for
     *    - switch
     */
    if (edad >= 18) {
        printf("Eres mayor de edad.\n");
    } else {
        printf("Eres menor de edad.\n");
    }

    /* Bucle while */
    int contador = 0;
    while (contador < 3) {
        printf("Contador (while): %d\n", contador);
        contador++;
    }

    /* Bucle for */
    for (int i = 0; i < 3; i++) {
        printf("Índice (for): %d\n", i);
    }

    /* Switch */
    int opcion = 2;
    switch (opcion) {
        case 1:
            printf("Opción 1 seleccionada.\n");
            break;
        case 2:
            printf("Opción 2 seleccionada.\n");
            break;
        default:
            printf("Opción desconocida.\n");
    }

    /* 6. Funciones y parámetros */
    int resultado = sumar(5, 7);
    printf("Resultado de sumar(5, 7): %d\n", resultado);

    return 0;
}

/*
 * 7. Definición de funciones
 *    - El prototipo (declaración) debe venir antes de la función main
 *    - La definición (cuerpo) viene después de main o en otro archivo
 */
int sumar(int a, int b) {
    return a + b;
}

